 18→const VisitedProfilePostCards = () =>{
 19→    const location = useLocation();
 20→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 21→    const {user, session} = useAuth();
 22→
 23→    const navigate = useNavigate();
 24→
 25→    const {ref, inView} = useInView({
 26→        threshold: 0.2
 27→    })
 28→
 29→    const {data: journalData, isLoading: isLoadingJournals, isFetchingNextPage, fetchNextPage, hasNextPage,} = useInfiniteQuery({
 30→        queryKey: ['visitedProfileJournals', userId, user?.userData?.[0]?.id],
 31→        queryFn: ({pageParam = null, queryKey}) => getVisitedUserJournals(pageParam, 5, queryKey[1], queryKey[2]),
 32→        getNextPageParam: (lastPage) => {
 33→            if(lastPage.hasMore){
 34→                const lastJournal = lastPage?.data[lastPage?.data.length - 1]
 35→                return new Date(lastJournal.created_at).toISOString();
 36→            } else {
 37→                return undefined
 38→            }
 39→        },
 40→        enabled: !!userId,
 41→        refetchOnWindowFocus: false
 42→    })
 43→
 44→    const clickContent = handleCLickContent(navigate);
 45→    const mutateViews = useAddViewsMutation(session);
 46→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) =>{
 47→        const formadata = new FormData();
 48→        formadata.append('journalId', journalId)
 49→        mutateViews.mutate(formadata);
 50→
 51→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc);
 52→    }
 53→
 54→    useEffect(() =>{
 55→        console.log(userId)
 56→    },[userId])
 57→
 58→    const [viewMode, setViewMode] = useState('grid');
 59→
 60→    useEffect(() =>{
 61→        if(!isFetchingNextPage && hasNextPage && inView){
 62→            fetchNextPage();
 63→        }
 64→    }, [inView, fetchNextPage, isFetchingNextPage, hasNextPage])
