 76→        isLoading,
 77→        hasNextPage,
 78→        fetchNextPage,
 79→        isFetchingNextPage,
 80→    } = useInfiniteQuery({
 81→        queryKey: ['storiesBrowse', statusFilter],
 82→        queryFn: ({ pageParam = null }) => getStories(12, pageParam, statusFilter, null, token),
 83→        getNextPageParam: (lastPage) => {
 84→            if (!lastPage?.hasMore || !lastPage.data?.length) return undefined;
 85→            return lastPage.data[lastPage.data.length - 1].created_at;
 86→        },
 87→        initialPageParam: null,
 88→        refetchOnWindowFocus: false,
 89→    });
 90→
 91→    const stories = data?.pages?.flatMap(p => p.data) || [];
 92→
 93→    return (
 94→        <div className="story-browser">
 95→            <div className="story-browser-header">
 96→                <h2 className="story-browser-title">Stories</h2>
 97→                {session && (
 98→                    <div className="story-browser-header-actions">
 99→                        <button
100→                            className="story-browser-my-btn"
101→                            onClick={() => navigate('/home/stories/library')}
102→                        >
103→                            My Library
104→                        </button>
105→                        <button
106→                            className="story-browser-my-btn"
107→                            onClick={() => navigate('/home/stories/dashboard')}
108→                        >
109→                            My Stories
110→                        </button>
111→                        <button
112→                            className="story-browser-new-btn"
113→                            onClick={() => navigate('/home/stories/new')}
114→                        >
115→                            + Write
116→                        </button>
117→                    </div>
118→                )}
119→            </div>
120→
121→            <div className="story-browser-filters">
122→                {STATUS_FILTERS.map(f => (
123→                    <button
124→                        key={f.label}
125→                        className={`story-filter-btn ${statusFilter === f.value ? 'story-filter-btn-active' : ''}`}
126→                        onClick={() => {
127→                            if (f.value) {
128→                                setSearchParams({ status: f.value });
129→                            } else {
130→                                setSearchParams({});
131→                            }
132→                        }}
133→                    >
134→                        {f.label}
135→                    </button>
136→                ))}
137→            </div>
138→
139→            {isLoading ? (
140→                <div className="story-browser-loading">
141→                    <BeatLoader size={10} color="var(--text-muted)" />
142→                </div>
143→            ) : stories.length === 0 ? (
144→                <div className="story-browser-empty">
145→                    <p>No stories found.</p>
146→                </div>
147→            ) : (
148→                <>
149→                    <div className="story-browser-grid">
150→                        {stories.map(story => (
151→                            <StoryCard
152→                                key={story.id}
153→                                story={story}
154→                                onClick={() => navigate(`/home/stories/${story.id}`)}
155→                            />
156→                        ))}
157→                    </div>
158→                    {hasNextPage && (
159→                        <div className="story-browser-load-more">
160→                            <button
161→                                className="story-browser-load-more-btn"
162→                                onClick={() => fetchNextPage()}
163→                                disabled={isFetchingNextPage}
164→                            >
165→                                {isFetchingNextPage ? (
166→                                    <BeatLoader size={8} color="var(--text-secondary)" />
167→                                ) : (
168→                                    'Load more'
169→                                )}
170→                            </button>
171→                        </div>
172→                    )}
173→                </>
174→            )}
175→        </div>
176→    );
177→};
178→
179→export default StoryBrowser;
