.profile-page-loading-container{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-backdrop-heavy);
    backdrop-filter: blur(25px);
    width: 100%;
    height:100vh;
    z-index: 3;
}
.profile-bg-picker-container{
    position: absolute;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    width: 400px;
    height: 400px;
    background-color: var(--bg-elevated);
    z-index: 136;
    padding: 1.25rem;
    border-radius: 18px;
    box-shadow: 0 12px 48px rgba(0, 0, 0, 0.12), 0 0 0 1px var(--border-light);
    gap: 1rem;
    color: var(--text-primary);
}
.profile-bg-picker-header{
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 600;
    font-size: 0.95rem;
    color: var(--text-heading);
}
.profile-bg-color-palette{
    display: flex;
    justify-content: space-evenly;
    width: 100%;
    height: 50px;
    padding: 1rem 0rem;
    border: 1px solid var(--border-light);
    border-radius: 10px;
}
.gradient-box{
    width: 50px;
    height: 50px;
    border-radius: 10px;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease, outline 0.2s ease;
    transform: scale(1) rotate(0deg);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    outline: 2px solid transparent;
    outline-offset: 2px;
}
.gradient-box.gradient-selected{
    outline-color: var(--accent-dark);
}
.gradient-box:hover{
    transform: scale(1.08) rotate(1.5deg);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.18);
}
.gradient-box:active{
    transform: scale(0.97);
}
.profile-bg-preview{
    position: relative;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    width: 100%;
    height: 50%;
    border-radius: 10px;
    gap: 1rem;
}
.controls{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    padding: 0.5rem;
    border-radius: 10px;
    background-color: var(--bg-elevated);
    position: relative;
    z-index: 10;
    margin-bottom: 0.2rem;
}

.remove-bg-preview{
    position: absolute;
    bottom: 80%;
    left: 85%;
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    padding: 0.2rem;
    background-color: var(--bg-backdrop-heavy);
    z-index: 10;
    margin-bottom: 0.2rem;
    border-radius: 50%;
    cursor: pointer;
}
.remove-bg-preview:hover{
    background-color: var(--bg-elevated);
}
.add-bgImage-bttn{
    position: absolute;
    bottom: 65px;
    width: 50px;
    height: 50px;
    border-radius: 10px;
    cursor: pointer;
    transition: ease-in-out 0.1s;
    transform: scale(1);
}
.add-bgImage-bttn:hover{
    transform: scale(1.1);
}

.cancel-save-container{
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    height: fit-content;
}
.cancel-button{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.8rem;
    background-color: var(--bg-hover);
    color: var(--text-primary);
    border-radius: 10px;
    cursor: pointer;
    transition: background-color 0.2s ease, transform 0.15s ease;
    font-weight: 600;
    font-size: 0.82rem;
}
.save-button{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.8rem;
    background-color: var(--accent-dark);
    color: var(--bg-primary);
    border-radius: 10px;
    cursor: pointer;
    transition: background-color 0.2s ease, transform 0.15s ease, box-shadow 0.2s ease;
    font-weight: 600;
    font-size: 0.82rem;
}
.save-button:hover{
   background-color: var(--accent-dark-hover);
   transform: translateY(-1px);
   box-shadow: 0 3px 12px rgba(0, 0, 0, 0.1);
}
.save-button:active{
   transform: translateY(0);
   box-shadow: none;
}
.cancel-button:hover{
   background-color: var(--bg-secondary);
}
.cancel-button:active{
   transform: scale(0.97);
}


.blurred-img-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(40px) saturate(1.2);
    transform: scale(1.4);
    animation: bgFadeIn 0.6s ease-out;
}
.blurred-gradient-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(100px) saturate(1.1);
    transform: scale(1.4);
    opacity: 0.1;
    animation: bgFadeIn 0.8s ease-out;
}
@keyframes bgFadeIn{
    from{ opacity: 0; transform: scale(1.5); }
    to{ opacity: 1; transform: scale(1.4); }
}
.profile-parent-container{
    position: relative;
    display: flex;
    justify-content: flex-start;
    align-items: center;
    width: 100%;
    height: 100vh;
    overflow-y: hidden;
    overflow-x: hidden;
}
