/* ═══════════════════════════════════════════════════
   Profile Stories Section
   ═══════════════════════════════════════════════════ */
.profile-stories-section {
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 90%;
    padding: 1.25rem;
    height: fit-content;
    margin-bottom: 1rem;
    margin-top: 1rem;
    border-radius: 18px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 0.7px solid var(--bg-glass-border);
    gap: 14px;
}

/* ═══════════════════════════════════════════════════
   Header Row
   ═══════════════════════════════════════════════════ */
.profile-stories-header-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 0 0.15rem;
}

.profile-stories-heading {
    margin: 0;
    font-family: var(--font-ui);
    font-size: 1.15rem;
    font-weight: 700;
    color: var(--text-heading);
    letter-spacing: -0.01em;
    line-height: 1;
}

.profile-stories-count {
    font-weight: 600;
    color: var(--text-muted);
    font-size: 0.95rem;
}

/* ═══════════════════════════════════════════════════
   Stories List
   ═══════════════════════════════════════════════════ */
.profile-stories-list {
    display: flex;
    flex-direction: column;
    gap: 10px;
    width: 100%;
}

/* ═══════════════════════════════════════════════════
   Individual Story Card (horizontal)
   ═══════════════════════════════════════════════════ */
.profile-story-card {
    display: flex;
    align-items: stretch;
    width: 100%;
    background-color: var(--bg-primary);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.25s ease, border-color 0.25s ease, transform 0.2s ease;
}

.profile-story-card:hover {
    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.07), 0 1px 6px rgba(0, 0, 0, 0.04);
    border-color: rgba(0, 0, 0, 0.09);
    transform: translateY(-1px);
}

[data-theme="dark"] .profile-story-card:hover {
    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.25), 0 1px 6px rgba(0, 0, 0, 0.15);
    border-color: rgba(255, 255, 255, 0.1);
}

/* ── Cover Thumbnail ── */
.profile-story-cover {
    width: 100px;
    min-height: 130px;
    flex-shrink: 0;
    overflow: hidden;
    background-color: var(--bg-secondary);
}

.profile-story-cover img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    transition: transform 0.25s ease, opacity 0.2s ease;
}

.profile-story-card:hover .profile-story-cover img {
    transform: scale(1.04);
    opacity: 0.92;
}

.profile-story-cover-placeholder {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: var(--bg-secondary);
}

/* ── Card Body ── */
.profile-story-body {
    display: flex;
    flex-direction: column;
    justify-content: center;
    gap: 0.4rem;
    padding: 0.75rem 1rem;
    flex: 1;
    min-width: 0;
}

.profile-story-title {
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.95rem;
    font-weight: 700;
    line-height: 1.35;
    letter-spacing: -0.02em;
    color: var(--text-heading);
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.profile-story-description {
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 400;
    line-height: 1.5;
    color: var(--text-body);
    opacity: 0.8;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

/* ── Meta Row (badge + stats) ── */
.profile-story-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-wrap: wrap;
    margin-top: 0.15rem;
}

.profile-story-badge {
    display: inline-flex;
    align-items: center;
    padding: 0.15rem 0.55rem;
    border-radius: 20px;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.65rem;
    font-weight: 600;
    letter-spacing: 0.01em;
    line-height: 1.5;
    user-select: none;
}

.profile-story-badge-ongoing {
    background: rgba(52, 199, 89, 0.12);
    color: #2daa55;
    border: 0.5px solid rgba(52, 199, 89, 0.25);
}

[data-theme="dark"] .profile-story-badge-ongoing {
    background: rgba(52, 199, 89, 0.15);
    color: #5fd88a;
}

.profile-story-badge-completed {
    background: rgba(88, 86, 214, 0.1);
    color: #5856d6;
    border: 0.5px solid rgba(88, 86, 214, 0.2);
}

[data-theme="dark"] .profile-story-badge-completed {
    background: rgba(88, 86, 214, 0.15);
    color: #8887e0;
}

.profile-story-badge-hiatus {
    background: rgba(255, 149, 0, 0.1);
    color: #d48100;
    border: 0.5px solid rgba(255, 149, 0, 0.2);
}

[data-theme="dark"] .profile-story-badge-hiatus {
    background: rgba(255, 149, 0, 0.15);
    color: #ffa833;
}

.profile-story-stats {
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
}

/* ── Tags ── */
.profile-story-tags {
    display: flex;
    gap: 5px;
    flex-wrap: wrap;
    margin-top: 0.1rem;
}

.profile-story-tag {
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    background: var(--bg-hover);
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 500;
    color: var(--text-secondary);
}

/* ── Author Row (for visited profile) ── */
.profile-story-author {
    display: flex;
    align-items: center;
    gap: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-secondary);
}

.profile-story-author-avatar {
    width: 18px;
    height: 18px;
    border-radius: 50%;
    object-fit: cover;
}

/* ═══════════════════════════════════════════════════
   Empty State
   ═══════════════════════════════════════════════════ */
.profile-stories-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 2.5rem 1rem;
    gap: 0.6rem;
    width: 100%;
}

.profile-stories-empty-icon {
    color: var(--text-muted);
    opacity: 0.4;
}

.profile-stories-empty-text {
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 500;
    color: var(--text-muted);
    opacity: 0.75;
}

/* ═══════════════════════════════════════════════════
   Mobile Responsive
   ═══════════════════════════════════════════════════ */
@media (max-width: 428px) {
    .profile-stories-section {
        width: 95%;
        padding: 0.6rem;
        gap: 10px;
        box-sizing: border-box;
    }

    .profile-stories-heading {
        font-size: 1rem;
    }

    .profile-stories-count {
        font-size: 0.85rem;
    }

    .profile-story-cover {
        width: 80px;
        min-height: 105px;
    }

    .profile-story-body {
        padding: 0.55rem 0.75rem;
        gap: 0.3rem;
    }

    .profile-story-title {
        font-size: 0.85rem;
    }

    .profile-story-description {
        font-size: 0.72rem;
        -webkit-line-clamp: 1;
    }

    .profile-story-card {
        border-radius: 12px;
    }

    .profile-story-card:hover {
        transform: none;
    }
}

