229→export const updateStoryService = async (storyId, userId, updates, coverFile) => {
230→    if (!storyId || !userId) {
231→        throw { status: 400, error: 'storyId and userId are required' };
232→    }
233→
234→    // Verify ownership (also grab title + description for embedding check)
235→    const { data: existing, error: fetchError } = await supabase
236→        .from('stories')
237→        .select('author_id, title, description')
238→        .eq('id', storyId)
239→        .single();
240→
241→    if (fetchError || !existing) {
242→        throw { status: 404, error: 'story not found' };
243→    }
244→    if (existing.author_id !== userId) {
245→        throw { status: 403, error: 'not authorized to update this story' };
246→    }
247→
248→    const updateData = {};
249→    if (updates.title !== undefined) {
250→        if (!updates.title || updates.title.trim().length === 0) {
251→            throw { status: 400, error: 'title cannot be empty' };
252→        }
253→        updateData.title = updates.title.trim();
254→    }
255→    if (updates.description !== undefined) {
256→        updateData.description = (updates.description || '').trim();
257→    }
258→    if (updates.status !== undefined && ['ongoing', 'completed', 'hiatus'].includes(updates.status)) {
259→        updateData.status = updates.status;
260→    }
261→    if (updates.privacy !== undefined && ['public', 'private'].includes(updates.privacy)) {
262→        updateData.privacy = updates.privacy;
263→    }
264→    if (updates.tags !== undefined) {
265→        let parsedTags = [];
266→        try {
267→            parsedTags = typeof updates.tags === 'string' ? JSON.parse(updates.tags) : updates.tags;
268→            if (!Array.isArray(parsedTags)) parsedTags = [];
269→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
270→        } catch {
271→            parsedTags = [];
272→        }
273→        updateData.tags = parsedTags;
274→    }
275→
276→    if (coverFile) {
277→        updateData.cover_url = await imageUploader(coverFile, userId, 'story-covers');
278→    }
279→
280→    if (Object.keys(updateData).length === 0) {
281→        throw { status: 400, error: 'no valid fields to update' };
282→    }
283→
284→    // Regenerate embedding if title or description changed
285→    if (updateData.title !== undefined || updateData.description !== undefined) {
286→        const resolvedTitle = updateData.title ?? existing.title;
287→        const resolvedDesc = updateData.description ?? (existing.description || '');
288→        const embedding = await GenerateEmbeddings(resolvedTitle, resolvedDesc);
289→        if (embedding && Array.isArray(embedding) && embedding.length > 0) {
290→            updateData.embedding = embedding;
291→        }
292→    }
293→
294→    const { data, error } = await supabase
295→        .from('stories')
296→        .update(updateData)
297→        .eq('id', storyId)
298→        .select('*')
299→        .single();
300→
301→    if (error) {
302→        console.error('supabase error updating story:', error.message);
303→        throw { status: 500, error: 'failed to update story' };
304→    }
305→
306→    return stripEmbedding(data);
307→};
