export const getStories = async (limit = 10, before = null, status = null, tag = null, token = null) => {
    const params = new URLSearchParams();
    params.set('limit', limit);
    if (before) params.set('before', before);
    if (status) params.set('status', status);
    if (tag) params.set('tag', tag);

    const headers = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await apiRequest(`${BASE_URL}/stories?${params}`, {
        method: 'GET',
        headers,
    });
    // ...
    return response.json();
};
```

**getUserStories (Line 119-132):**
```javascript
export const getUserStories = async (userId, token = null) => {
    const headers = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await apiRequest(`${BASE_URL}/stories/user/${userId}`, {
        method: 'GET',
        headers,
    });
    // ...
    return response.json();
};
```

**Comparison:**
- `getStories`: Accepts `limit` and `before` cursor params ✅
- `getUserStories`: NO pagination params ❌ (just userId in URL path)

