 1→import { useNavigate } from 'react-router-dom';
 2→import { useAuth } from '../../../Context/useAuth';
 3→import { useUserStories } from '../../Stories/hooks/useStoryData';
 4→import { motion } from 'framer-motion';
 5→import { MoonLoader } from 'react-spinners';
 6→import './ProfileStoriesSection.css';
 7→
 8→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 9→
10→const ProfileStoriesSection = () => {
11→    const { user, session } = useAuth();
12→    const token = session?.access_token;
13→    const userId = user?.userData?.[0]?.id;
14→    const navigate = useNavigate();
15→
16→    const { data, isLoading } = useUserStories(userId, token);
17→    const stories = Array.isArray(data) ? data : (data?.stories || []);
18→
19→    if (isLoading) {
20→        return (
21→            <div className="profile-postcards-loading-container">
22→                <MoonLoader loading={true} color="var(--loader-color)" size={20} speedMultiplier={0.5} />
23→            </div>
24→        );
25→    }
26→
27→    return (
28→        <div className="profile-stories-section">
29→            <div className="profile-stories-header-row">
30→                <h2 className="profile-stories-heading">
31→                    Stories <span className="profile-stories-count">({stories.length})</span>
32→                </h2>
33→            </div>
34→
35→            {!stories.length ? (
36→                <div className="profile-stories-empty">
37→                    <svg className="profile-stories-empty-icon" xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="currentColor">
38→                        <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
39→                    </svg>
40→                    <p className="profile-stories-empty-text">No stories yet.</p>
41→                </div>
42→            ) : (
43→                <div className="profile-stories-list">
44→                    {stories.map((story, index) => (
45→                        <motion.div
46→                            key={story.id}
47→                            className="profile-story-card"
48→                            initial={{ opacity: 0, y: 12 }}
49→                            animate={{ opacity: 1, y: 0 }}
50→                            transition={{ duration: 0.3, ease: 'easeOut', delay: index * 0.04 }}
51→                            onClick={() => navigate(`/home/stories/${story.id}`)}
52→                        >
53→                            <div className="profile-story-cover">
54→                                {story.cover_url ? (
55→                                    <img src={story.cover_url} alt={story.title} loading="lazy" />
56→                                ) : (
57→                                    <div className="profile-story-cover-placeholder">
58→                                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="var(--text-muted)" opacity="0.4">
59→                                            <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z" />
60→                                        </svg>
61→                                    </div>
62→                                )}
63→                            </div>
64→                            <div className="profile-story-body">
65→                                <h3 className="profile-story-title">{story.title}</h3>
66→                                {story.description && (
67→                                    <p className="profile-story-description">{story.description}</p>
68→                                )}
69→                                <div className="profile-story-meta">
70→                                    <span className={`profile-story-badge profile-story-badge-${story.status}`}>
71→                                        {STATUS_LABELS[story.status] || story.status}
72→                                    </span>
73→                                    <span className="profile-story-stats">
74→                                        {story.vote_count || 0} votes &middot; {story.read_count || 0} reads
75→                                    </span>
76→                                </div>
77→                                {story.tags && story.tags.length > 0 && (
78→                                    <div className="profile-story-tags">
79→                                        {story.tags.slice(0, 3).map(tag => (
80→                                            <span key={tag} className="profile-story-tag">{tag}</span>
81→                                        ))}
82→                                    </div>
83→                                )}
84→                            </div>
85→                        </motion.div>
86→                    ))}
87→                </div>
88→            )}
89→        </div>
90→    );
91→};
92→
93→export default ProfileStoriesSection;
