  2→import multer from "multer";
  3→import supabase from "../services/supabase.js";
  4→
  5→import {
  6→    createStoryController,
  7→    getStoriesController,
  8→    getStoryByIdController,
  9→    updateStoryController,
 10→    deleteStoryController,
 11→    getMyStoriesController,
 12→    getUserStoriesController,
 13→} from "../controller/storyController.js";
 14→
 15→import {
 16→    createChapterController,
 17→    getChapterController,
 18→    updateChapterController,
 19→    deleteChapterController,
 20→    reorderChaptersController,
 21→} from "../controller/chapterController.js";
 22→
 23→import {
 24→    toggleVoteController,
 25→    toggleLibraryController,
 26→    getMyLibraryController,
 27→    getCommentsController,
 28→    getCommentCountsController,
 29→    addCommentController,
 30→    saveProgressController,
 31→    getProgressController,
 32→} from "../controller/storyInteractController.js";
 33→
 34→const storyRouter = express.Router();
 35→
 36→const upload = multer({
 37→    storage: multer.memoryStorage(),
 38→    limits: { fileSize: 10 * 1024 * 1024 },
 39→}).single('image');
 40→
 41→// ── Auth middleware (same pattern as routes.js) ──
 42→
 43→const extractBearerToken = (authHeader = "") => {
 44→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 45→    if (!trimmed) return "";
 46→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 47→    if (bearerMatch?.[1]) return bearerMatch[1].trim();
 48→    return trimmed;
 49→};
 50→
 51→const resolveAuthUser = async (token) => {
 52→    if (!token) return { user: null, error: null };
 53→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
 54→    if (authError || !authData?.user?.id) {
 55→        return { user: null, error: authError || new Error("missing user id") };
 56→    }
 57→    return { user: authData.user, error: null };
 58→};
 59→
 60→const requireAuth = async (req, res, next) => {
 61→    const token = extractBearerToken(req.headers?.authorization);
 62→    if (!token) return res.status(401).json({ error: 'not authorized' });
 63→    const { user, error } = await resolveAuthUser(token);
 64→    if (error || !user?.id) return res.status(401).json({ error: 'not authorized' });
 65→    req.userId = user.id;
 66→    req.authUser = user;
 67→    return next();
 68→};
 69→
 70→const optionalAuth = async (req, _res, next) => {
 71→    const token = extractBearerToken(req.headers?.authorization);
 72→    if (!token) return next();
 73→    const { user } = await resolveAuthUser(token);
 74→    if (user?.id) {
 75→        req.userId = user.id;
 76→        req.authUser = user;
 77→    }
 78→    return next();
 79→};
 80→
 81→// ── Story routes ──
 82→storyRouter.post('/stories', requireAuth, upload, createStoryController);
 83→storyRouter.get('/stories', optionalAuth, getStoriesController);
 84→storyRouter.get('/stories/my', requireAuth, getMyStoriesController);
 85→storyRouter.get('/stories/library', requireAuth, getMyLibraryController);
 86→storyRouter.get('/stories/user/:userId', optionalAuth, getUserStoriesController);
 87→storyRouter.get('/stories/:storyId', optionalAuth, getStoryByIdController);
 88→storyRouter.patch('/stories/:storyId', requireAuth, upload, updateStoryController);
 89→storyRouter.delete('/stories/:storyId', requireAuth, deleteStoryController);
